  1→import { useRef, useCallback } from 'react';
  2→import { getStarColor, getStarRadius, simpleHash } from '../utils/starUtils';
  3→
  4→// ── Constants ──────────────────────────────────────────────────────────
  5→const MAX_SPEED = 12;
  6→const ACCEL = 0.25;
  7→const BRAKE = 0.15;
  8→const FRICTION = 0.985;
  9→const TURN_RATE = 0.035;
 10→const MIN_Z = 0.5;
 11→const MAX_Z = 800;
 12→const SPAWN_Z_RANGE = 400;
 13→const SORT_INTERVAL = 5;
 14→const TARGET_DIST_MAX = 150;
 15→const TARGET_Z_MIN = 2;
 16→const TWO_PI = Math.PI * 2;
 17→
 18→/** Parse "#5f92ff" → { r, g, b } */
 19→const parseHex = (hex) => ({
 20→    r: parseInt(hex.slice(1, 3), 16),
 21→    g: parseInt(hex.slice(3, 5), 16),
 22→    b: parseInt(hex.slice(5, 7), 16),
 23→});
 24→
 25→/** Seeded pseudo-random from integer seed */
 26→const seededRandom = (seed) => {
 27→    let s = seed | 0;
 28→    return () => {
 29→        s = (s * 1664525 + 1013904223) | 0;
 30→        return ((s >>> 0) / 4294967296);
 31→    };
 32→};
 33→
 34→const useRocketMode = () => {
 35→    const isActiveRef = useRef(false);
 36→    const rocketPosRef = useRef({ x: 0, y: 0 });
 37→    const headingRef = useRef(-Math.PI / 2);
 38→    const velocityRef = useRef(0);
 39→    const starsRef = useRef([]);
 40→    const sortedIndicesRef = useRef([]);
 41→    const keysRef = useRef({ w: false, s: false, a: false, d: false });
 42→    const targetIndexRef = useRef(-1);
 43→    const frameRef = useRef(0);
 44→    const layerRef = useRef(null);
 45→    const rafRef = useRef(null);
 46→    const stageSizeRef = useRef({ width: 0, height: 0 });
 47→
 48→    const sortStars = useCallback(() => {
 49→        const stars = starsRef.current;
 50→        const indices = sortedIndicesRef.current;
 51→        // Simple insertion sort — fast for nearly-sorted arrays
 52→        for (let i = 1; i < indices.length; i++) {
 53→            const key = indices[i];
 54→            let j = i - 1;
 55→            while (j >= 0 && stars[indices[j]].z < stars[key].z) {
 56→                indices[j + 1] = indices[j];
 57→                j--;
 58→            }
 59→            indices[j + 1] = key;
 60→        }
 61→    }, []);
 62→
 63→    const tick = useCallback(() => {
 64→        if (!isActiveRef.current) return;
 65→
 66→        const keys = keysRef.current;
 67→        const pos = rocketPosRef.current;
 68→        const stars = starsRef.current;
 69→        const size = stageSizeRef.current;
 70→
 71→        // ── Heading ────────────────────────────────────────────────
 72→        if (keys.a) headingRef.current -= TURN_RATE;
 73→        if (keys.d) headingRef.current += TURN_RATE;
 74→
 75→        // ── Velocity ───────────────────────────────────────────────
 76→        if (keys.w) {
 77→            velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
 78→        } else if (keys.s) {
 79→            velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
 80→        } else {
 81→            velocityRef.current *= FRICTION;
 82→            if (velocityRef.current < 0.01) velocityRef.current = 0;
 83→        }
 84→
 85→        const heading = headingRef.current;
 86→        const velocity = velocityRef.current;
 87→
 88→        // ── Position ───────────────────────────────────────────────
 89→        pos.x += Math.cos(heading) * velocity;
 90→        pos.y += Math.sin(heading) * velocity;
 91→
 92→        // ── Z update + recycle ─────────────────────────────────────
 93→        const zStep = velocity * 0.5;
 94→        for (let i = 0; i < stars.length; i++) {
 95→            const star = stars[i];
 96→            star.z -= zStep;
 97→            if (star.z < MIN_Z) {
 98→                star.z = MAX_Z - Math.random() * SPAWN_Z_RANGE;
 99→                star.worldX = pos.x + (Math.random() - 0.5) * 4000;
100→                star.worldY = pos.y + (Math.random() - 0.5) * 4000;
101→            }
102→        }
103→
104→        // ── Sort (every N frames) ─────────────────────────────────
105→        frameRef.current++;
106→        if (frameRef.current % SORT_INTERVAL === 0) {
107→            sortStars();
108→        }
109→
110→        // ── Target detection ───────────────────────────────────────
111→        const cx = size.width / 2;
112→        const cy = size.height / 2;
113→        const cosH = Math.cos(-heading + Math.PI / 2);
114→        const sinH = Math.sin(-heading + Math.PI / 2);
115→        let bestIdx = -1;
116→        let bestDist = TARGET_DIST_MAX;
117→
118→        for (let i = 0; i < stars.length; i++) {
119→            const star = stars[i];
120→            if (star.z < TARGET_Z_MIN) continue;
121→            const relX = star.worldX - pos.x;
122→            const relY = star.worldY - pos.y;
123→            const rotX = relX * cosH - relY * sinH;
124→            const rotY = relX * sinH + relY * cosH;
125→            const projX = cx + rotX / star.z;
126→            const projY = cy + rotY / star.z;
127→            const dx = projX - cx;
128→            const dy = projY - cy;
129→            const dist = Math.sqrt(dx * dx + dy * dy);
130→            if (dist < bestDist) {
131→                bestDist = dist;
132→                bestIdx = i;
133→            }
134→        }
135→        targetIndexRef.current = bestIdx;
136→
137→        // ── Redraw ─────────────────────────────────────────────────
138→        if (layerRef.current) {
139→            layerRef.current.batchDraw();
140→        }
141→
142→        rafRef.current = requestAnimationFrame(tick);
143→    }, [sortStars]);
144→
145→    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
146→        stageSizeRef.current = stageSize;
147→        rocketPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
148→        headingRef.current = -Math.PI / 2;
149→        velocityRef.current = 0;
150→        frameRef.current = 0;
151→        targetIndexRef.current = -1;
152→
153→        // Build star array from posts
154→        const stars = [];
155→        for (let i = 0; i < galaxyPosts.length; i++) {
156→            const post = galaxyPosts[i];
157→            const uid = post.users?.id ?? post.user_id;
158→            const likeCount = post.like_count != null
159→                ? post.like_count
160→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
161→                    ? post.likes[0].count : 0);
162→            const color = getStarColor(uid);
163→            const rng = seededRandom(simpleHash(post.id || String(i)));
164→            stars.push({
165→                postId: post.id,
166→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
167→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
168→                z: MIN_Z + rng() * (MAX_Z - MIN_Z),
169→                color,
170→                colorRgb: parseHex(color),
171→                radius: getStarRadius(likeCount),
172→                title: post.title || 'Untitled',
173→                authorName: post.users?.name || post.user_name || 'Anonymous',
174→                post,
175→            });
176→        }
177→
178→        starsRef.current = stars;
179→
180→        // Build sorted indices (far → near)
181→        const indices = new Array(stars.length);
182→        for (let i = 0; i < stars.length; i++) indices[i] = i;
183→        indices.sort((a, b) => stars[b].z - stars[a].z);
184→        sortedIndicesRef.current = indices;
185→
186→        // Key listeners
187→        const onKeyDown = (e) => {
188→            const key = e.key.toLowerCase();
189→            if (key === 'w' || key === 'arrowup') keysRef.current.w = true;
190→            if (key === 's' || key === 'arrowdown') keysRef.current.s = true;
191→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
192→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
193→        };
194→        const onKeyUp = (e) => {
195→            const key = e.key.toLowerCase();
196→            if (key === 'w' || key === 'arrowup') keysRef.current.w = false;
197→            if (key === 's' || key === 'arrowdown') keysRef.current.s = false;
198→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
199→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
200→        };
201→
202→        window.addEventListener('keydown', onKeyDown);
203→        window.addEventListener('keyup', onKeyUp);
204→
205→        // Store cleanup refs
206→        keysRef.current = { w: false, s: false, a: false, d: false };
207→        isActiveRef.current = true;
208→
209→        // Store listener refs for cleanup
210→        rocketPosRef.current._onKeyDown = onKeyDown;
211→        rocketPosRef.current._onKeyUp = onKeyUp;
212→
213→        // Start rAF
214→        rafRef.current = requestAnimationFrame(tick);
215→    }, [tick]);
216→
217→    const exit = useCallback(() => {
218→        isActiveRef.current = false;
219→        if (rafRef.current) {
220→            cancelAnimationFrame(rafRef.current);
221→            rafRef.current = null;
222→        }
223→        // Remove key listeners
224→        const pos = rocketPosRef.current;
225→        if (pos._onKeyDown) {
226→            window.removeEventListener('keydown', pos._onKeyDown);
227→            window.removeEventListener('keyup', pos._onKeyUp);
228→            delete pos._onKeyDown;
229→            delete pos._onKeyUp;
230→        }
231→        keysRef.current = { w: false, s: false, a: false, d: false };
232→    }, []);
233→
234→    const project = useCallback((star, cx, cy) => {
235→        const pos = rocketPosRef.current;
236→        const heading = headingRef.current;
237→        const relX = star.worldX - pos.x;
238→        const relY = star.worldY - pos.y;
239→        const cosH = Math.cos(-heading + Math.PI / 2);
240→        const sinH = Math.sin(-heading + Math.PI / 2);
241→        const rotX = relX * cosH - relY * sinH;
242→        const rotY = relX * sinH + relY * cosH;
243→        return {
244→            projX: cx + rotX / star.z,
245→            projY: cy + rotY / star.z,
246→            scale: 1 / star.z,
247→        };
248→    }, []);
249→
250→    const getTargetedPost = useCallback(() => {
251→        const idx = targetIndexRef.current;
252→        if (idx < 0 || idx >= starsRef.current.length) return null;
253→        return starsRef.current[idx].post;
254→    }, []);
255→
256→    const getSpeedRatio = useCallback(() => {
257→        return velocityRef.current / MAX_SPEED;
258→    }, []);
259→
260→    return {
261→        enter,
262→        exit,
263→        layerRef,
264→        starsRef,
265→        sortedIndicesRef,
266→        rocketPos: rocketPosRef,
267→        heading: headingRef,
268→        velocity: velocityRef,
269→        targetIndexRef,
270→        stageSizeRef,
271→        project,
272→        isActive: isActiveRef,
273→        getTargetedPost,
274→        getSpeedRatio,
275→    };
276→};
277→
278→export default useRocketMode;
