  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→
  4→const TWO_PI = Math.PI * 2;
  5→const SPEED_LINE_COUNT = 30;
  6→
  7→const RocketLayer = React.memo(({ rocketMode }) => {
  8→    const {
  9→        layerRef, starsRef, sortedIndicesRef, velocity, targetIndexRef,
 10→        stageSizeRef, project, getSpeedRatio,
 11→    } = rocketMode;
 12→
 13→    const shapeRef = useRef(null);
 14→    const timeRef = useRef(0);
 15→
 16→    // Attach the Konva Layer ref so the hook can call batchDraw
 17→    const layerCallbackRef = useCallback((node) => {
 18→        layerRef.current = node;
 19→    }, [layerRef]);
 20→
 21→    // Keep time ticking for pulsing effects
 22→    useEffect(() => {
 23→        const update = () => {
 24→            timeRef.current = performance.now();
 25→        };
 26→        const id = setInterval(update, 16);
 27→        return () => clearInterval(id);
 28→    }, []);
 29→
 30→    return (
 31→        <Layer ref={layerCallbackRef} listening={false}>
 32→            <Shape
 33→                ref={shapeRef}
 34→                sceneFunc={(ctx) => {
 35→                    const size = stageSizeRef.current;
 36→                    const cx = size.width / 2;
 37→                    const cy = size.height / 2;
 38→                    const stars = starsRef.current;
 39→                    const sorted = sortedIndicesRef.current;
 40→                    const speedRatio = getSpeedRatio();
 41→                    const time = timeRef.current || performance.now();
 42→                    const targetIdx = targetIndexRef.current;
 43→                    const bufferX = size.width / 2 + 200;
 44→                    const bufferY = size.height / 2 + 200;
 45→
 46→                    // ── 1. Speed lines (behind stars) ──────────────────
 47→                    if (speedRatio > 0.4) {
 48→                        const lineAlpha = (speedRatio - 0.4) / 0.6;
 49→                        ctx.strokeStyle = `rgba(180,210,255,${lineAlpha * 0.3})`;
 50→                        ctx.lineWidth = 1;
 51→
 52→                        for (let i = 0; i < SPEED_LINE_COUNT; i++) {
 53→                            const angle = (i / SPEED_LINE_COUNT) * TWO_PI;
 54→                            const innerR = 80 + Math.sin(time * 0.002 + i) * 20;
 55→                            const outerR = innerR + 60 + speedRatio * 200;
 56→                            ctx.beginPath();
 57→                            ctx.moveTo(
 58→                                cx + Math.cos(angle) * innerR,
 59→                                cy + Math.sin(angle) * innerR
 60→                            );
 61→                            ctx.lineTo(
 62→                                cx + Math.cos(angle) * outerR,
 63→                                cy + Math.sin(angle) * outerR
 64→                            );
 65→                            ctx.stroke();
 66→                        }
 67→                    }
 68→
 69→                    // ── 2. Stars (painter's algorithm, far first) ──────
 70→                    for (let si = 0; si < sorted.length; si++) {
 71→                        const idx = sorted[si];
 72→                        const star = stars[idx];
 73→                        const { projX, projY, scale } = project(star, cx, cy);
 74→
 75→                        // Viewport cull
 76→                        if (projX < cx - bufferX || projX > cx + bufferX ||
 77→                            projY < cy - bufferY || projY > cy + bufferY) continue;
 78→
 79→                        const baseRadius = star.radius * scale * 40;
 80→                        if (baseRadius < 0.3) continue;
 81→
 82→                        const stretchX = 1 + speedRatio * 2.5;
 83→                        const opacity = Math.max(0.1, 1 - speedRatio * 0.6);
 84→                        const drawR = Math.min(baseRadius, 60);
 85→                        const { r, g, b } = star.colorRgb;
 86→
 87→                        ctx.save();
 88→                        ctx.translate(projX, projY);
 89→                        ctx.scale(stretchX, 1);
 90→
 91→                        // Outer glow
 92→                        const glowR = drawR * 2.5;
 93→                        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, glowR);
 94→                        grad.addColorStop(0, `rgba(${r},${g},${b},${opacity * 0.5})`);
 95→                        grad.addColorStop(0.4, `rgba(${r},${g},${b},${opacity * 0.15})`);
 96→                        grad.addColorStop(1, 'rgba(0,0,0,0)');
 97→                        ctx.beginPath();
 98→                        ctx.arc(0, 0, glowR, 0, TWO_PI);
 99→                        ctx.fillStyle = grad;
100→                        ctx.fill();
101→
102→                        // Core (white-hot center)
103→                        const coreR = drawR * 0.4;
104→                        ctx.beginPath();
105→                        ctx.arc(0, 0, Math.max(coreR, 0.5), 0, TWO_PI);
106→                        ctx.fillStyle = `rgba(255,255,255,${opacity * 0.9})`;
107→                        ctx.fill();
108→
109→                        ctx.restore();
110→
111→                        // ── 3. Targeting bracket ───────────────────────
112→                        if (idx === targetIdx) {
113→                            const pulse = 0.6 + 0.4 * Math.sin(time * 0.004);
114→                            const bracketSize = Math.max(drawR * stretchX * 4, 18);
115→                            const half = bracketSize / 2;
116→                            const arm = bracketSize * 0.35;
117→
118→                            ctx.strokeStyle = `rgba(0,255,255,${pulse})`;
119→                            ctx.lineWidth = 1.5;
120→                            ctx.setLineDash([3, 3]);
121→
122→                            // Top-left
123→                            ctx.beginPath();
124→                            ctx.moveTo(projX - half, projY - half + arm);
125→                            ctx.lineTo(projX - half, projY - half);
126→                            ctx.lineTo(projX - half + arm, projY - half);
127→                            ctx.stroke();
128→
129→                            // Top-right
130→                            ctx.beginPath();
131→                            ctx.moveTo(projX + half - arm, projY - half);
132→                            ctx.lineTo(projX + half, projY - half);
133→                            ctx.lineTo(projX + half, projY - half + arm);
134→                            ctx.stroke();
135→
136→                            // Bottom-right
137→                            ctx.beginPath();
138→                            ctx.moveTo(projX + half, projY + half - arm);
139→                            ctx.lineTo(projX + half, projY + half);
140→                            ctx.lineTo(projX + half - arm, projY + half);
141→                            ctx.stroke();
142→
143→                            // Bottom-left
144→                            ctx.beginPath();
145→                            ctx.moveTo(projX - half + arm, projY + half);
146→                            ctx.lineTo(projX - half, projY + half);
147→                            ctx.lineTo(projX - half, projY + half - arm);
148→                            ctx.stroke();
149→
150→                            ctx.setLineDash([]);
151→                        }
152→                    }
153→                }}
154→                perfectDrawEnabled={false}
155→                listening={false}
156→            />
157→        </Layer>
158→    );
159→});
160→
161→RocketLayer.displayName = 'RocketLayer';
162→
163→export default RocketLayer;
164→

 1→import { useState, useEffect, useRef, useCallback } from 'react';
 2→import styles from '../Universe.module.css';
 3→
 4→const RocketHUD = ({ rocketMode, onExit, onInteract }) => {
 5→    const [speed, setSpeed] = useState(0);
 6→    const [targetInfo, setTargetInfo] = useState(null);
 7→    const pollRef = useRef(null);
 8→
 9→    // Poll refs at 10 Hz for HUD display
10→    useEffect(() => {
11→        pollRef.current = setInterval(() => {
12→            setSpeed(rocketMode.getSpeedRatio());
13→
14→            const idx = rocketMode.targetIndexRef.current;
15→            const stars = rocketMode.starsRef.current;
16→            if (idx >= 0 && idx < stars.length) {
17→                const star = stars[idx];
18→                setTargetInfo({ title: star.title, author: star.authorName });
19→            } else {
20→                setTargetInfo(null);
21→            }
22→        }, 100);
23→
24→        return () => {
25→            if (pollRef.current) clearInterval(pollRef.current);
26→        };
27→    }, [rocketMode]);
28→
29→    // Key bindings for Enter/Space (interact) and Escape (exit)
30→    const handleKey = useCallback((e) => {
31→        if (e.key === 'Enter' || e.key === ' ') {
32→            e.preventDefault();
33→            onInteract();
34→        } else if (e.key === 'Escape') {
35→            e.preventDefault();
36→            onExit();
37→        }
38→    }, [onInteract, onExit]);
39→
40→    useEffect(() => {
41→        window.addEventListener('keydown', handleKey);
42→        return () => window.removeEventListener('keydown', handleKey);
43→    }, [handleKey]);
44→
45→    return (
46→        <div className={styles.rocketHud}>
47→            {/* Exit button */}
48→            <button className={styles.rocketExitBtn} onClick={onExit}>
49→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
50→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
51→                </svg>
52→                Exit Rocket
53→            </button>
54→
55→            {/* Target info (below center) */}
56→            {targetInfo && (
57→                <div className={styles.rocketTarget}>
58→                    <div className={styles.rocketTargetTitle}>{targetInfo.title}</div>
59→                    <div className={styles.rocketTargetAuthor}>by {targetInfo.author}</div>
60→                    <div className={styles.rocketTargetPrompt}>Press ENTER to read</div>
61→                </div>
62→            )}
63→
64→            {/* Speed bar */}
65→            <div className={styles.rocketSpeedBar}>
66→                <span className={styles.rocketSpeedLabel}>SPD</span>
67→                <div className={styles.rocketSpeedTrack}>
68→                    <div
69→                        className={styles.rocketSpeedFill}
70→                        style={{ width: `${Math.round(speed * 100)}%` }}
71→                    />
72→                </div>
73→                <span className={styles.rocketSpeedValue}>{Math.round(speed * 100)}%</span>
74→            </div>
75→
76→            {/* Controls hint */}
77→            <div className={styles.rocketControls}>
78→                <span>W/S Throttle</span>
79→                <span>A/D Turn</span>
80→                <span>ENTER Read</span>
81→                <span>ESC Exit</span>
82→            </div>
83→        </div>
84→    );
85→};
86→
87→export default RocketHUD;
88→

 1→export const STAR_COLORS = ['#5f92ff', '#ff5fa2', '#5fffb0', '#ffd75f', '#b05fff', '#ff8a5f'];
 2→
 3→export const MIN_UNIVERSE_ZOOM = 0.02;
 4→export const MAX_UNIVERSE_ZOOM = 5;
 5→export const HOME_SCALE = 0.8;
 6→export const GUEST_SCALE = 0.05;
 7→
 8→export const simpleHash = (str) => {
 9→    let h = 0;
10→    for (let i = 0; i < str.length; i++) {
11→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
12→    }
13→    return Math.abs(h);
14→};
15→
16→export const userHomeCoords = (userId) => {
17→    if (!userId) return { x: 0, y: 0 };
18→    const mid = Math.floor(userId.length / 2);
19→    const xHash = simpleHash(userId.slice(0, mid));
20→    const yHash = simpleHash(userId.slice(mid));
21→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
22→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
23→    return { x, y };
24→};
25→
26→export const getStarColor = (userId) => {
27→    if (!userId) return STAR_COLORS[0];
28→    return STAR_COLORS[simpleHash(userId) % STAR_COLORS.length];
29→};
30→
31→export const getStarRadius = (likeCount) => {
32→    const likes = Math.min(likeCount || 0, 20);
33→    return 6 + likes * 0.3;
34→};
35→
36→export const extractSnippet = (post) => {
37→    if (post.post_type === 'canvas' && post.canvas_doc?.snippets) {
38→        return post.canvas_doc.snippets
39→            .map(s => s?.text || '')
40→            .filter(Boolean)
41→            .join(' ')
42→            .slice(0, 200);
43→    }
44→    if (typeof post.content === 'string') {
45→        try {
46→            const parsed = JSON.parse(post.content);
47→            const extractText = (node) => {
48→                if (!node) return '';
49→                if (typeof node.text === 'string') return node.text;
50→                if (Array.isArray(node.children)) {
51→                    return node.children.map(extractText).join('');
52→                }
53→                return '';
54→            };
55→            return extractText(parsed.root || parsed).slice(0, 200);
56→        } catch {
57→            return post.content.slice(0, 200);
58→        }
59→    }
60→    return '';
61→};
62→
63→export const hexToRgba = (hex, alpha) => {
64→    const r = parseInt(hex.slice(1, 3), 16);
65→    const g = parseInt(hex.slice(3, 5), 16);
66→    const b = parseInt(hex.slice(5, 7), 16);
67→    return `rgba(${r},${g},${b},${alpha})`;
68→};
